window.HK_LC9 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["They are touching a price tag.", "They are entering a mall.", "They are purchasing some jewelry.", "They are holding shopping bags."], "optko": ["그들은 가격표를 만지고 있다.", "그들은 쇼핑몰에 들어가고 있다.", "그들은 보석을 구매하고 있다.", "그들은 쇼핑백을 들고 있다."], "ans": 3, "audio": "Test09_01.mp3", "img": "hk_t9_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["They are stretching on a tennis court.", "They are celebrating after a match.", "One of the men is swinging a bat.", "One of the men is throwing a ball into a net."], "optko": ["그들은 테니스 경기장에서 스트레칭을 하고 있다.", "그들은 경기 후에 축하하고 있다.", "남자들 중 한 명이 라켓을 휘두르고 있다.", "남자들 중 한 명이 네트로 공을 던지고 있다."], "ans": 2, "audio": "Test09_02.mp3", "img": "hk_t9_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["One of the men is making a phone call.", "One of the men is pressing a button.", "One of the men is writing with a pencil.", "One of the men is handing over a card."], "optko": ["남자들 중 한 명이 전화를 걸고 있다.", "남자들 중 한 명이 버튼을 누르고 있다.", "남자들 중 한 명이 연필로 적고 있다.", "남자들 중 한 명이 카드를 넘겨주고 있다."], "ans": 3, "audio": "Test09_03.mp3", "img": "hk_t9_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["Customers are looking over some menus.", "An outdoor seating area is full.", "A waiter is reaching toward a table.", "A brick wall is being constructed."], "optko": ["손님들이 메뉴를 보고 있다.", "야외 좌석 공간이 가득 찼다.", "한 웨이터가 테이블을 향해 손을 뻗고 있다.", "벽돌 담이 건설되고 있다."], "ans": 2, "audio": "Test09_04.mp3", "img": "hk_t9_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Some walkways are empty.", "Some workers are repairing a sidewalk.", "Some signboards have been put out.", "Some people are being led by a tour guide."], "optko": ["보도들이 비어 있다.", "작업자들이 보도를 수리하고 있다.", "몇몇 간판들이 내다 놓아져 있다.", "몇몇 사람들이 여행 가이드에 의해 인솔되고 있다."], "ans": 2, "audio": "Test09_05.mp3", "img": "hk_t9_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Some windows overlook a parking area.", "Some bushes are being trimmed.", "A bench has been placed next to a tree.", "Chimneys are sticking up from some roofs."], "optko": ["창문들이 주차장을 내려다본다.", "덤불이 다듬어지고 있다.", "벤치가 나무 옆에 놓여 있다.", "굴뚝들이 지붕들 위로 튀어나와 있다."], "ans": 3, "audio": "Test09_06.mp3", "img": "hk_t9_q6.jpg"}, {"n": 7, "part": 2, "q": "What is included in the brochure?", "qko": "소책자 안에 무엇이 포함되어 있나요?", "opts": ["Images of the park.", "After they were handed out.", "Yes, be sure to include them."], "optko": ["공원의 사진들이요.", "그것들이 배분된 이후에요.", "네, 그것들을 반드시 포함시키도록 하세요."], "ans": 0, "audio": "Test09_07.mp3"}, {"n": 8, "part": 2, "q": "Who is Glenwood Fashions' celebrity spokesperson?", "qko": "Glenwood 패션사의 유명 인사 대변인이 누구인가요?", "opts": ["Maybe Mr. Grant can show her.", "Ann Kim is the main one.", "An order of sweaters."], "optko": ["아마 Mr. Grant가 그녀에게 보여줄 수 있을 거예요.", "Ann Kim이 주요 인사예요.", "스웨터 주문 건이요."], "ans": 1, "audio": "Test09_08.mp3"}, {"n": 9, "part": 2, "q": "Where will you film the news clip?", "qko": "당신은 어디에서 뉴스 동영상을 촬영할 건가요?", "opts": ["That's not being done anymore.", "For tonight's broadcast.", "With a film crew."], "optko": ["그건 더 이상 진행되지 않고 있어요.", "오늘 밤 방송을 위해서요.", "영화 제작진과요."], "ans": 0, "audio": "Test09_09.mp3"}, {"n": 10, "part": 2, "q": "When will the snowstorm reach Oslo?", "qko": "눈보라가 언제 오슬로에 도착할까요?", "opts": ["You'll want to wear a warm hat.", "Around 5 P.M.", "I can't reach that high."], "optko": ["당신은 따뜻한 모자를 쓰고 싶을 거예요.", "오후 5시쯤이요.", "저는 그렇게 높이 닿을 수 없어요."], "ans": 1, "audio": "Test09_10.mp3"}, {"n": 11, "part": 2, "q": "Are guests charged for the resort's valet parking service?", "qko": "손님들이 리조트의 대리 주차 서비스 요금을 청구받나요?", "opts": ["I guess there's enough left.", "I'm going to ask the front desk staff now.", "It's a ballet performance."], "optko": ["충분히 남은 것 같아요.", "제가 지금 안내 데스크의 직원에게 물어볼게요.", "그것은 발레 공연이에요."], "ans": 1, "audio": "Test09_11.mp3"}, {"n": 12, "part": 2, "q": "Was last week's lecture about renewable energy or recycling?", "qko": "지난주의 강의가 재생 가능한 에너지에 관한 것이었나요, 아니면 재활용에 관한 것이었나요?", "opts": ["Environmental issues are important.", "We learned about solar power.", "The lecture starts in an hour."], "optko": ["환경 문제는 중요해요.", "우리는 태양열에 관해 배웠어요.", "강의가 한 시간 후에 시작해요."], "ans": 1, "audio": "Test09_12.mp3"}, {"n": 13, "part": 2, "q": "Why isn't the conference being promoted yet?", "qko": "왜 컨퍼런스가 아직 홍보되지 않고 있나요?", "opts": ["He received the promotion.", "To provide name tags to attendees.", "Radio commercials have already been aired."], "optko": ["그는 승진했어요.", "참석자들에게 이름표를 제공하기 위해서요.", "라디오 광고들이 이미 방송되었어요."], "ans": 2, "audio": "Test09_13.mp3"}, {"n": 14, "part": 2, "q": "Which department store did you previously manage?", "qko": "당신은 이전에 어느 백화점을 관리했나요?", "opts": ["I watched the entire preview.", "It was an outlet in Nashville.", "Let the supervisors know."], "optko": ["저는 예고편 전체를 봤어요.", "내슈빌에 있는 할인점이었어요.", "관리자들에게 알려주세요."], "ans": 1, "audio": "Test09_14.mp3"}, {"n": 15, "part": 2, "q": "Laureen will give her presentation in five minutes.", "qko": "Laureen이 5분 후에 발표를 할 거예요.", "opts": ["Some slide show edits.", "Oh, that's sooner than I thought.", "We'll give them a present."], "optko": ["슬라이드 쇼 편집이요.", "아, 제가 생각했던 것보다 이르네요.", "우리는 그들에게 선물을 줄 거예요."], "ans": 1, "audio": "Test09_15.mp3"}, {"n": 16, "part": 2, "q": "Have you decided which bookshelf design you like more?", "qko": "어느 책꽂이 디자인이 더 좋은지 결정했나요?", "opts": ["Both look good to me.", "I designed this poster.", "Mostly for my novels."], "optko": ["저는 둘 다 좋아 보여요.", "제가 이 포스터를 디자인했어요.", "주로 제 소설들에 관해서요."], "ans": 0, "audio": "Test09_16.mp3"}, {"n": 17, "part": 2, "q": "Do you intend to analyze our customer survey results?", "qko": "당신이 우리 고객 설문조사 결과를 분석할 생각이신가요?", "opts": ["Some information from a questionnaire.", "Stacey was given that task.", "The race results just came in."], "optko": ["설문지의 정보들이요.", "Stacey가 그 업무를 받았어요.", "경주 결과가 막 나왔어요."], "ans": 1, "audio": "Test09_17.mp3"}, {"n": 18, "part": 2, "q": "The invitations for the event were sent out, weren't they?", "qko": "행사 초대장들이 발송되었죠, 그렇지 않나요?", "opts": ["Vendors expect checks to be sent out.", "The auction will raise funds for charity.", "They're still being prepared."], "optko": ["상인들은 수표가 발송되기를 기대해요.", "경매는 자선기금을 모을 거예요.", "그것들은 아직 준비되고 있어요."], "ans": 2, "audio": "Test09_18.mp3"}, {"n": 19, "part": 2, "q": "How much quicker is driving than walking to the shopping mall?", "qko": "쇼핑몰까지 차로 가는 것은 걷는 것보다 얼마나 더 빠른가요?", "opts": ["We could save about five minutes.", "She has worked here for 10 years.", "Rome is an hour away by car."], "optko": ["우리는 아마 5분 정도를 아낄 수 있을 거예요.", "그녀는 여기에서 10년 동안 일해 왔어요.", "로마는 차로 한 시간 거리에 있어요."], "ans": 0, "audio": "Test09_19.mp3"}, {"n": 20, "part": 2, "q": "When is the highway construction expected to be finished?", "qko": "고속도로 공사가 언제 끝날 것으로 예상되나요?", "opts": ["At Exit 71.", "Hopefully, by early May.", "All the way to Boston."], "optko": ["71번 출구에요.", "바라건대, 5월 초까지요.", "보스턴까지 내내요."], "ans": 1, "audio": "Test09_20.mp3"}, {"n": 21, "part": 2, "q": "Would you like me to place these clean towels here?", "qko": "이 깨끗한 수건들을 여기에 놓을까요?", "opts": ["I appreciate the opportunity.", "They're made of cotton.", "Please put them on the table."], "optko": ["기회를 주셔서 감사해요.", "그것들은 면으로 만들어졌어요.", "테이블 위에 놓아주세요."], "ans": 2, "audio": "Test09_21.mp3"}, {"n": 22, "part": 2, "q": "What style of jewelry are you looking for?", "qko": "어떤 스타일의 보석을 찾고 있나요?", "opts": ["I prefer pieces with a classic look.", "I've looked everywhere for it.", "The line is selling quite well."], "optko": ["저는 고전적인 모양의 제품을 선호해요.", "저는 이걸 위해 모든 곳을 찾아봤어요.", "그 종류는 꽤 잘 팔리고 있어요."], "ans": 0, "audio": "Test09_22.mp3"}, {"n": 23, "part": 2, "q": "Will you be able to finish reviewing these proposals today?", "qko": "오늘 이 제안서들을 검토하는 걸 끝낼 수 있나요?", "opts": ["To propose a new project.", "I'll be done by lunch.", "Complete the decorations as soon as you can."], "optko": ["새 프로젝트를 제안하기 위해서요.", "점심시간까지 끝낼 거예요.", "당신이 할 수 있는 한 빨리 장식을 마무리하세요."], "ans": 1, "audio": "Test09_23.mp3"}, {"n": 24, "part": 2, "q": "Are you planning to visit our company's branch in Pittsburgh next month?", "qko": "당신은 다음 달에 우리 회사의 피츠버그 지점을 방문할 계획인가요?", "opts": ["It's paid every month.", "Some of the plans contained miscalculations.", "Not until my colleague returns from his trip."], "optko": ["이것은 매달 지불돼요.", "도면들 중 일부에는 계산 착오가 들어 있었어요.", "제 동료가 여행에서 돌아오기 전까지는 아니에요."], "ans": 2, "audio": "Test09_24.mp3"}, {"n": 25, "part": 2, "q": "We can take photos with the singer after her concert, right?", "qko": "우리가 콘서트 이후에 그 가수와 사진을 찍을 수 있을 거예요, 그렇죠?", "opts": ["We can, according to this flyer.", "The picture is too large.", "I own her album."], "optko": ["이 전단지에 따르면 그럴 수 있어요.", "사진이 너무 커요.", "저는 그녀의 앨범을 갖고 있어요."], "ans": 0, "audio": "Test09_25.mp3"}, {"n": 26, "part": 2, "q": "How many covers for these chairs do you need?", "qko": "당신은 이 의자들을 위한 덮개가 얼마나 필요한가요?", "opts": ["The sitting area near the window.", "Let me count quickly.", "Sure, I can cover for him."], "optko": ["창문 가까이에 있는 좌석 공간이요.", "제가 얼른 세어 볼게요.", "물론이죠, 제가 그의 일을 대신할 수 있어요."], "ans": 1, "audio": "Test09_26.mp3"}, {"n": 27, "part": 2, "q": "I can't find the blueprints for the Skyward Building.", "qko": "Skyward 건물에 관한 청사진들을 찾을 수 없어요.", "opts": ["It contains over 50 floors.", "That depends on the print's colors.", "I'm happy to help you look for them."], "optko": ["그곳에는 50개가 넘는 층들이 있어요.", "그것은 인쇄물의 색상에 달려 있어요.", "제가 당신이 그것들을 찾는 걸 도와줄게요."], "ans": 2, "audio": "Test09_27.mp3"}, {"n": 28, "part": 2, "q": "Have you responded to Ms. Bridge's text message to our engineering team?", "qko": "Ms. Bridge가 우리 기술팀에게 보낸 문자 메시지에 답장을 보냈나요?", "opts": ["The entire crew received a bonus.", "No, a messaging application.", "I'll get back to her later."], "optko": ["팀 전체가 보너스를 받았어요.", "아니요, 메시지 애플리케이션이요.", "나중에 그녀에게 다시 연락할게요."], "ans": 2, "audio": "Test09_28.mp3"}, {"n": 29, "part": 2, "q": "The factory in China can increase its output, can't it?", "qko": "중국에 있는 공장이 생산량을 늘릴 수 있죠, 그렇지 않나요?", "opts": ["Updated manufacturing procedures.", "I don't think that's possible.", "I'll put them outside."], "optko": ["업데이트된 제조 과정들이요.", "가능할 것 같지 않아요.", "제가 그것들을 밖에 놓을게요."], "ans": 1, "audio": "Test09_29.mp3"}, {"n": 30, "part": 2, "q": "Do you have any idea who choreographed this dance performance?", "qko": "당신은 이 댄스 공연의 안무를 누가 맡았는지 아시나요?", "opts": ["It might be indicated in the program.", "In order to brainstorm ideas.", "I'll try to think of something else."], "optko": ["아마 예정표에 나와 있을 거예요.", "방안들을 생각해 내기 위해서요.", "다른 무언가를 생각해 볼게요."], "ans": 0, "audio": "Test09_30.mp3"}, {"n": 31, "part": 2, "q": "Where should we keep surplus ingredients?", "qko": "여분의 재료들을 어디에 보관해야 하나요?", "opts": ["The kitchen has nice appliances.", "What have chefs here done previously?", "Some of the extra potatoes."], "optko": ["부엌에 좋은 기기들이 있어요.", "이곳의 셰프들은 이전에 어떻게 했나요?", "여분의 감자들 몇 개요."], "ans": 1, "audio": "Test09_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test09_32-34.mp3", "qs": [{"n": 32, "q": "What does the man say he has to do tomorrow?", "opts": ["Prepare a guest list", "Collect some additional data", "Travel out of state", "Present some information"], "ans": 3, "ko": "남자는 내일 무엇을 해야 한다고 말하는가?"}, {"n": 33, "q": "What is the woman working on?", "opts": ["A safety manual", "A financial report", "A funding proposal", "A conference agenda"], "ans": 1, "ko": "여자는 무엇을 작업하고 있는가?"}, {"n": 34, "q": "According to the woman, why should the man approach to Greta?", "opts": ["She has already begun an assignment.", "She is new to a company.", "She is stressed out about a deadline.", "She is knowledgeable about a topic."], "ans": 3, "ko": "여자에 따르면, 남자는 왜 Greta에게 연락해야 하는가?"}], "script": [{"sp": "M", "en": "Joanne, I'm supposed to compile data related to our budget and then show it to our CEO tomorrow morning. I've collected the financial data and could use your help with the slide show.", "ko": "Joanne, 저는 저희 예산과 관련된 자료를 수집해서 내일 아침에 최고 경영자에게 보여드리기로 되어 있어요. 재정 자료를 모았는데 슬라이드 쇼에 대해 당신의 도움을 받을 수 있을 것 같아요."}, {"sp": "W", "en": "Sorry. I'm really busy writing this sales report. But if you need help figuring out how to put together a slide show, I know there are some good tutorials online.", "ko": "미안해요. 저는 이 매출 보고서를 쓰느라 정말 바빠요. 하지만 슬라이드 쇼를 어떻게 만드는지 알아내는 데 도움이 필요하다면, 온라인에 좋은 설명서들이 있다는 걸 알아요."}, {"sp": "M", "en": "Thank you, but that's not the issue. I'm on a tight deadline, so I was just hoping to get some help analyzing figures.", "ko": "감사하지만 그게 문제가 아니에요. 마감 기한이 빠듯해서 수치를 분석하는 데 도움을 받고 싶었어요."}, {"sp": "W", "en": "In that case, Greta can probably help you. She's familiar with our budget, and I believe she has some downtime this afternoon.", "ko": "그렇다면, 아마 Greta가 도움을 줄 수 있을 거예요. 그녀는 우리 예산을 잘 알고 있고 제 생각에는 그녀가 오늘 오후에 한가한 시간이 좀 있을 거예요."}, {"sp": "M", "en": "OK. I'll find her and ask.", "ko": "알겠어요. 제가 그녀를 찾아서 물어볼게요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test09_35-37.mp3", "qs": [{"n": 35, "q": "What did the woman discuss during a phone call?", "opts": ["A price estimate", "A delayed order", "A payment method", "A malfunctioning system"], "ans": 3, "ko": "여자는 전화로 무엇을 논의하였는가?"}, {"n": 36, "q": "What does the man say the speakers will do after lunch?", "opts": ["Hold a staff discussion", "Stop by a housing complex", "Modify some quotes", "Mark dates on a schedule"], "ans": 1, "ko": "남자는 화자들이 점심 이후에 무엇을 할 것이라고 말하는가?"}, {"n": 37, "q": "What does the woman mean when she says, \"the Gilmore job will be taken care of tomorrow\"?", "opts": ["She is confused by some directions.", "She believes a customer is correct.", "She received approval from her boss.", "She has not contacted a client yet."], "ans": 0, "ko": "여자는 \"Gilmore 작업은 내일 진행될 거잖아요\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "W", "en": "I just got off the phone with a customer. There's an issue with his home security hardware. It's not working at all. I told him I'd head over there in a little while to work on it.", "ko": "저는 방금 고객과의 전화 통화를 마쳤어요. 그의 가정 보안 장비에 문제가 있어요. 그것이 전혀 작동하지 않는대요. 제가 그걸 작업하기 위해 잠시 후에 그곳에 가겠다고 말했어요."}, {"sp": "M", "en": "That's fine as long as you can return by noon. Just remember, we've still got to go to the Gilmore Apartments right after lunch. Multiple door handles need to be swapped out for ones with keypads.", "ko": "당신이 정오까지 돌아올 수 있다면 괜찮아요. 우리는 여전히 점심 직후에 Gilmore 아파트로 가야 한다는 것을 기억해 주세요. 여러 개의 손잡이를 키패드가 있는 것들로 교체해야 해요."}, {"sp": "W", "en": "But, the Gilmore job will be taken care of tomorrow. That's what Ken told me.", "ko": "그렇지만, Gilmore 작업은 내일 진행될 거잖아요. Ken이 저에게 그렇게 얘기해 줬어요."}, {"sp": "M", "en": "No, it's today. It says so right here on our calendar.", "ko": "아니요, 오늘이에요. 여기 우리 달력에 그렇게 적혀 있어요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test09_38-40.mp3", "qs": [{"n": 38, "q": "Who most likely is the man?", "opts": ["A sales representative", "A construction worker", "A building manager", "A landscape specialist"], "ans": 1, "ko": "남자는 누구인 것 같은가?"}, {"n": 39, "q": "What problem is mentioned?", "opts": ["A client is not currently at home.", "A deck has been damaged.", "A crew arrived later than expected.", "A forecast is unfavorable."], "ans": 3, "ko": "어떤 문제가 언급되는가?"}, {"n": 40, "q": "What will most likely happen on Thursday?", "opts": ["Some permits will be issued.", "Some tools will be removed from a yard.", "A structure will be inspected.", "A product will be returned."], "ans": 2, "ko": "목요일에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "W", "en": "You and your crew have done an exceptional job building my deck. I can't wait to see what it'll look like once the wood has been stained. It's going to make my backyard much more inviting.", "ko": "당신과 당신의 팀은 제 목제 테라스 짓는 일을 정말 뛰어나게 해주셨어요. 목제가 염색되고 나면 어떤 모습일지 빨리 보고 싶어요. 그건 제 뒷마당을 훨씬 더 매력적으로 만들 거예요."}, {"sp": "M", "en": "I'm glad you're satisfied. As for staining the surface, however, we unfortunately won't be able to take care of that today. I just heard on the radio that a rainstorm will hit the area within half an hour.", "ko": "만족하신다니 기쁘네요. 그런데 표면을 염색하는 것과 관련해서, 저희는 안타깝지만 그걸 오늘 처리하지 못할 거예요. 폭풍우가 30분 내로 이 지역에 이를 거라는 것을 방금 라디오에서 들었거든요."}, {"sp": "W", "en": "Oh, that's too bad. Do you have any idea when you might be able to wrap everything up?", "ko": "아, 정말 안타깝네요. 언제쯤 모든 것을 마무리 지을 수 있을지 아시나요?"}, {"sp": "M", "en": "We'll stop by on Thursday to check if the boards have dried. If so, we'll finish then. Otherwise, it won't be until Friday.", "ko": "판자가 다 말랐는지 확인하기 위해 목요일에 들를게요. 그렇게 되면 그때 마무리 지을게요. 그렇지 않으면, 금요일이 나 되어야 할 거예요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Am", "audio": "Test09_41-43.mp3", "qs": [{"n": 41, "q": "Why must the woman go out of town?", "opts": ["To promote some publications", "To conduct some reporting", "To organize an event", "To interview for a job"], "ans": 1, "ko": "여자는 왜 다른 지역으로 가야 하는가?"}, {"n": 42, "q": "According to the man, what will Paula Miron give a talk on?", "opts": ["Journalism classes", "Networking events", "Social media", "Workplace diversity"], "ans": 2, "ko": "남자에 따르면, Paula Miron은 무엇에 대해 강연할 것인가?"}, {"n": 43, "q": "What does the man offer to do?", "opts": ["Share some notes", "Record a talk", "Buy a ticket", "Save a seat"], "ans": 3, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "M", "en": "Hey, Kelly. Are you going to the journalism convention this weekend? Last year's event was very informative.", "ko": "안녕하세요, Kelly. 이번 주말에 저널리즘 컨벤션에 갈 예정인가요? 작년 행사는 굉장히 유익했어요."}, {"sp": "W", "en": "Well, I have to travel out of town to watch a major basketball game and write an article on it. I won't be returning until late on Saturday, but I hope to go on Sunday.", "ko": "글쎄요, 저는 중요한 농구 시합을 보고 그것에 대한 기사를 쓰기 위해 다른 지역으로 가야 해요. 저는 토요일 늦게나 돌아올 예정인데, 일요일에는 가고 싶어요."}, {"sp": "M", "en": "That means you'll get to watch Paula Miron's speech on how social networking sites affect people's exposure to the news. Since I'll be going a bit early, do you want me to save a chair for you?", "ko": "그건 당신이 소셜 네트워킹 사이트가 사람들의 뉴스에 대한 노출에 어떻게 영향을 주는지에 대한 Paula Miron의 연설을 볼 수 있을 거라는 걸 의미해요. 제가 약간 일찍 가니까, 당신을 위한 자리를 따로 맡아드릴까요?"}, {"sp": "W", "en": "Yeah, if you don't mind. I'd appreciate that.", "ko": "네, 괜찮으시다면요. 그렇게 해주시면 감사할 것 같아요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Br", "audio": "Test09_44-46.mp3", "qs": [{"n": 44, "q": "Why is the man visiting the woman?", "opts": ["To return an item", "To discuss a project", "To inspect a device", "To plan a trip"], "ans": 0, "ko": "남자는 왜 여자를 방문하는가?"}, {"n": 45, "q": "What does the man ask the woman about?", "opts": ["When a warranty will expire", "Who provided a present", "Where a product was acquired", "Which product sizes are available"], "ans": 2, "ko": "남자는 여자에게 무엇에 관해 문의하는가?"}, {"n": 46, "q": "What will the woman do next?", "opts": ["Check the size of a device", "Show the man some promotional material", "Drive to a store", "Fill out a shipping document"], "ans": 1, "ko": "여자는 다음에 무엇을 할 것인가?"}], "script": [{"sp": "M", "en": "Anna, you left your tablet in my office. Here it is. By the way, I like the case. The leather is really high quality. Did you buy it at a local store?", "ko": "Anna, 당신이 태블릿을 제 사무실에 놓고 갔어요, 여기 있어요. 그건 그렇고, 그 케이스가 마음에 드네요. 가죽이 정말 고급이에요. 그것을 지역 상점에서 사셨나요?"}, {"sp": "W", "en": "No. One of my relatives runs a leather goods shop in Italy. She sells these and other handmade items. Are you interested in getting one?", "ko": "아니요. 제 친척 중 한 명이 이탈리아에서 가죽 제품 상점을 운영해요. 그녀는 이것들과 다른 수제품들을 팔아요. 하나 구매하는 데 관심이 있으신가요?"}, {"sp": "M", "en": "Yeah, I recently purchased a new device, so that would be great. Does she ship them internationally?", "ko": "네, 제가 최근에 새 기기를 구매해서 그렇게 하면 좋겠네요. 그녀는 국제 배송을 해주나요?"}, {"sp": "W", "en": "For a fee. You know what? Stay here for a minute. I've got a brochure about her business in my car. I think you'll find it informative.", "ko": "수수료를 받고요. 있잖아요. 잠시 여기 있어보세요. 제 차에 그녀의 업체에 대한 책자가 있어요. 당신이 유익하다고 생각하실 것 같아요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test09_47-49.mp3", "qs": [{"n": 47, "q": "Who most likely is the man?", "opts": ["A travel agent", "A flight attendant", "A hotel worker", "A bus driver"], "ans": 2, "ko": "남자는 누구인 것 같은가?"}, {"n": 48, "q": "What is the problem?", "opts": ["A trip has been delayed.", "A bus is fully booked.", "A room was not cleaned.", "A schedule is inaccurate."], "ans": 1, "ko": "무엇이 문제인가?"}, {"n": 49, "q": "When will the woman most likely depart for the airport?", "opts": ["At 8:30 A.M.", "At 10:00 A.M.", "At 11:30 A.M.", "At 1:00 P.M."], "ans": 0, "ko": "여자는 언제 공항으로 출발할 것 같은가?"}], "script": [{"sp": "W", "en": "Hello. I'd like to take your hotel's airport shuttle bus tomorrow at 10 A.M. Can you arrange that for me?", "ko": "안녕하세요. 저는 내일 오전 10시에 호텔의 공항 셔틀버스를 타고 싶어요. 그걸 준비해주실 수 있으신가요?"}, {"sp": "M", "en": "I'm sorry. That shuttle is already full. But, I can place you on . . . um . . . the 11:30 A.M. bus instead.", "ko": "죄송합니다. 그 셔틀버스는 이미 만석입니다. 하지만, 저는 손님을… 음… 대신 오전 11시 30분 버스에 자리를 잡아 드릴 수 있어요."}, {"sp": "W", "en": "No, I'm afraid that would be too late as my flight is scheduled to depart at 1 o'clock. Could I go at another time?", "ko": "아니요, 제 항공편이 1시에 출발할 예정이기 때문에 유감스럽게 그건 너무 늦을 거예요. 다른 시간에 갈 수 있을까요?"}, {"sp": "M", "en": "Let me see. Yes, we have a spot open at 8:30 A.M. You'll be a bit early for your flight, but there are no other times available. So, I think you'll have to take that one.", "ko": "한번 볼게요. 네, 오전 8시 30분에 자리가 있네요. 비행기를 타시기에 조금 일찍 도착하겠지만, 이용 가능한 다른 시간이 없습니다. 그래서 그걸 타셔야 할 것 같습니다."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "M-Am / W-Au", "audio": "Test09_50-52.mp3", "qs": [{"n": 50, "q": "What is the conversation mainly about?", "opts": ["Some appliance sales", "A vehicle launch", "Some test results", "A safety procedure"], "ans": 2, "ko": "대화는 주로 무엇에 관한 것인가?"}, {"n": 51, "q": "What does the woman have yet to do?", "opts": ["Find a distributor", "Modify a recent order", "Announce news to a team", "Evaluate some car parts"], "ans": 3, "ko": "여자는 여전히 무엇을 해야 하는가?"}, {"n": 52, "q": "What does the woman mean when she says, \"I have the day off tomorrow\"?", "opts": ["A request cannot be met.", "An assistant will handle her duties.", "She will complete a project today.", "She plans to work at home."], "ans": 0, "ko": "여자는 \"저는 내일 쉬는 날이에요\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "M", "en": "Debora, there you are. Do you have the results of the crash test for our jeep prototype? I'm curious whether improvements will need to be made to the design.", "ko": "Debora, 여기 계셨군요. 우리 지프차 견본의 충돌 검사 결과를 갖고 있나요? 저는 설계에 개선 사항이 적용되어야 할지 궁금해요."}, {"sp": "W", "en": "Well, the hood was badly damaged during the low-speed test. I think we might have to make it out of a different material on the final model. I still have to examine both the front and rear doors.", "ko": "음, 저속 검사 중에 덮개가 심하게 손상되었어요. 최종 모델에서는 그걸 다른 소재로 만들어야 할 것 같아요. 저는 아직 앞문과 뒷문을 검사해야 해요."}, {"sp": "M", "en": "I see. Well, after finishing with that, please write a report. I'd like to have it before the end of the workweek.", "ko": "그렇군요. 음, 그걸 완료한 후에 보고서를 작성해 주세요. 저는 그걸 이번 주 근무가 끝나기 전에 받고 싶어요."}, {"sp": "W", "en": "Oh, I have the day off tomorrow.", "ko": "아, 저는 내일 쉬는 날이에요."}, {"sp": "M", "en": "Sorry, I forgot. In that case, just get it to me by early next week.", "ko": "미안해요, 제가 잊었었네요. 그렇다면, 다음 주 초까지 제게 주세요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "M / W1 / W2", "audio": "Test09_53-55.mp3", "qs": [{"n": 53, "q": "What problem does the man mention?", "opts": ["Some supplies are running low.", "Some carpets are the wrong color.", "A water machine is leaking.", "A bucket cannot be located."], "ans": 2, "ko": "남자는 무슨 문제를 언급하는가?"}, {"n": 54, "q": "What is mentioned about the facilities director?", "opts": ["He is on a break.", "He provided some directions.", "He is currently busy.", "He agreed to cover a cost."], "ans": 0, "ko": "시설 담당자에 관해 무엇이 언급되는가?"}, {"n": 55, "q": "What will Olivia do next?", "opts": ["Head to an elevator", "Consult a directory", "Resume a meeting", "Fix an error"], "ans": 1, "ko": "Olivia는 다음에 무엇을 할 것인가?"}], "script": [{"sp": "M", "en": "The water dispenser near the elevator started dripping and a small pool of water collected on the carpet.", "ko": "엘리베이터 근처의 정수기에서 물이 뚝뚝 떨어지기 시작했고, 카펫에 작은 물웅덩이가 생겼어요."}, {"sp": "W1", "en": "Oh, really? That could cause permanent damage to the floor.", "ko": "아, 정말이요? 그건 바닥에 영구적인 손상을 초래할 수도 있겠네요."}, {"sp": "M", "en": "I had the same concern. For the time being, I've placed a bucket under the device to catch the drops. But, someone should let the facilities director know.", "ko": "저도 같은 걱정을 했어요. 일단은 물방울들을 받기 위해 그 기기 아래에 양동이를 놓았어요. 하지만, 누군가 시설 담당자에게 알려줘야 해요."}, {"sp": "W2", "en": "He actually isn't here this week. He's vacationing in Greece.", "ko": "그는 사실 이번 주에 여기 없어요. 그리스에서 휴가를 보내고 있거든요."}, {"sp": "W1", "en": "Right. Well, I'm sure he'd want us to have a plumber come and make the necessary repairs. Olivia, do you mind looking up a plumber in the area quickly?", "ko": "맞아요. 음, 틀림없이 그는 우리가 배관공을 불러 필요한 수리를 하게 하길 원할 거예요. Olivia, 이 지역의 배관공을 신속히 알아봐주실 수 있나요?"}, {"sp": "W2", "en": "Sure thing. I've got a phone book at my desk.", "ko": "물론이죠. 제 책상에 전화번호부가 있어요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "M / W", "audio": "Test09_56-58.mp3", "qs": [{"n": 56, "q": "What does the man most likely want to acquire?", "opts": ["A real estate license", "A textbook", "A scholarship", "A teaching degree"], "ans": 0, "ko": "남자는 무엇을 얻길 원하는 것 같은가?"}, {"n": 57, "q": "What does the woman say about the in-person sessions?", "opts": ["They are open to the public.", "They are offered on weekends.", "They last an hour.", "They are free of charge."], "ans": 2, "ko": "여자는 오프라인 수업들에 관해 무엇을 말하는가?"}, {"n": 58, "q": "What does the man ask the woman to do?", "opts": ["Explain a recent change", "Provide a Web address", "Reschedule a lesson", "Print out a receipt"], "ans": 1, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가?"}], "script": [{"sp": "M", "en": "Hi. I'd like to know more about your class on becoming certified as a realtor.", "ko": "안녕하세요. 공인 부동산 중개인이 되는 것에 대한 수업에 대해 좀 더 알고 싶습니다."}, {"sp": "W", "en": "Sure. We have two in-person sessions—one at 10 A.M. and the other at 2 P.M. They're both 60 minutes long and are held on Tuesdays and Thursdays.", "ko": "물론이죠. 저희는 오프라인 수업이 두 개 있는데, 하나는 오전 10시이고 다른 하나는 오후 2시입니다. 둘 다 60분씩이며 화요일과 목요일에 열립니다."}, {"sp": "M", "en": "Actually, I want to take an evening class. Is that an option?", "ko": "사실, 저는 저녁 수업을 듣고 싶어요. 그런 선택권이 있나요?"}, {"sp": "W", "en": "Not at the moment. We do have an online course, though. You can take the lessons any time you want, as long as you finish within two months. It can be signed up for on our Web site.", "ko": "지금으로서는 아니에요. 그렇지만 저희는 온라인 수업이 있어요. 두 달 안에만 끝낸다면 당신이 원하는 어떤 시간에든 강의들을 들을 수 있어요. 저희 웹사이트에서 등록하실 수 있어요."}, {"sp": "M", "en": "Could you give me that address?", "ko": "그 주소를 주실 수 있나요?"}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "W1 / W2 / M", "audio": "Test09_59-61.mp3", "qs": [{"n": 59, "q": "What will take place tomorrow?", "opts": ["A restaurant opening", "A company party", "An orientation session", "A business visit"], "ans": 3, "ko": "내일 무슨 일이 일어날 것인가?"}, {"n": 60, "q": "According to the man, what will be ready this afternoon?", "opts": ["Some visual materials", "Some mobile applications", "A travel itinerary", "A lunch menu"], "ans": 0, "ko": "남자에 따르면, 무엇이 오늘 오후에 준비될 것인가?"}, {"n": 61, "q": "What does Linda offer to do?", "opts": ["Drive to a station", "Wait at an arrival gate", "Compare different services", "Arrange a ride"], "ans": 3, "ko": "Linda는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W1", "en": "Is everything ready for tomorrow? It's important that we impress Ms. Stefan when she comes to our office since she may invest much-needed capital in our company.", "ko": "내일을 위한 모든 준비가 되었나요? Ms. Stefan이 우리 회사에 매우 필요한 자금을 투자할 수도 있기 때문에 그녀가 우리 사무실에 올 때 우리가 그녀에게 깊은 인상을 주는 것이 중요해요."}, {"sp": "W2", "en": "My part's done. A table at Gigi Bistro has been booked for lunch—specifically, a private room.", "ko": "제 부분은 끝났어요. Gigi 식당에 점심 식사를 예약했어요, 구체적으로는 개인실로요."}, {"sp": "W1", "en": "Perfect. How about you, Darnell? Have you organized our sales data into charts that we can present?", "ko": "완벽해요. 당신은 어떤가요, Darnell? 우리가 발표할 수 있도록 판매량 자료를 도표로 정리하셨나요?"}, {"sp": "M", "en": "I still haven't finished, but they'll be ready this afternoon.", "ko": "아직 완료하지 못했는데 오늘 오후에는 준비될 거예요."}, {"sp": "W1", "en": "OK, good. One final thing, Linda. Ms. Stefan must be met at the train station upon her arrival.", "ko": "네, 좋아요. 마지막으로 한 가지 더요, Linda. Ms. Stefan이 도착하는 것에 맞춰 기차역으로 마중을 가야 해요."}, {"sp": "W2", "en": "OK. I'll contact the taxi service we normally use.", "ko": "알겠어요. 우리가 보통 이용하는 택시 서비스에 연락할게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "M / W", "audio": "Test09_62-64.mp3", "qs": [{"n": 62, "q": "What does the woman say about Langston Hall?", "opts": ["It was easily accessible.", "It offered ample space.", "It was advertised on the Internet.", "It lacked sufficient seating."], "ans": 1, "ko": "여자는 Langston 홀에 관해 무엇을 말하는가?"}, {"n": 63, "q": "Look at the graphic. According to the woman, which aspect of an event was the most expensive?", "opts": ["Venue", "Decorations", "Gift bags", "Food"], "ans": 3, "ko": "시각 자료를 보시오. 여자에 따르면, 행사의 어떤 부문에 비용이 가장 많이 들었는가?"}, {"n": 64, "q": "What does the man suggest?", "opts": ["Extending a break", "Apologizing to some staff", "Requesting a full refund", "Searching for different vendors"], "ans": 0, "ko": "남자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "Ms. Woods. I have the results from the questionnaire we distributed after last week's company gathering.", "ko": "Ms. Woods, 저는 지난주 회사 모임 이후에 우리가 나눠주었던 설문지의 결과를 갖고 있어요."}, {"sp": "W", "en": "Great, Nelson. Let me take a quick look . . . Oh! I'm pleased that so many employees were satisfied with the facility. I liked it too—it was much larger than we expected.", "ko": "좋아요, Nelson. 잠깐 볼게요… 아! 이렇게 많은 직원들이 시설에 만족했다는 사실이 기쁘네요. 우리가 예상했던 것보다 훨씬 더 커서 저도 좋았어요."}, {"sp": "M", "en": "Yes. We'll have to use Langston Hall when we hold similar events in the future. It was very reasonable.", "ko": "네. 앞으로도 비슷한 행사를 개최할 때 Langston 홀을 이용해야겠어요. 가격도 매우 적당했어요."}, {"sp": "W", "en": "Indeed. But it's a shame that the most expensive aspect of the event received the least amount of praise.", "ko": "정말 그래요. 하지만 행사에서 비용이 가장 많이 든 부문이 칭찬을 가장 적게 받은 것은 유감이네요."}, {"sp": "M", "en": "You're right . . . Also, while not in the survey, some staff said the lunch break was rushed. Next time, we should offer more time to eat.", "ko": "맞아요… 또한, 설문에는 없지만 일부 직원들은 점심시간이 서둘러 진행되었다고 이야기했어요. 다음 번에는 식사할 시간을 더 많이 주어야겠어요."}], "gimg": "hk_t9_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au, W-Am", "audio": "Test09_65-67.mp3", "qs": [{"n": 65, "q": "What will be delivered at 1 P.M.?", "opts": ["Some construction material", "Some heavy machinery", "Some office furniture", "Some architectural blueprints"], "ans": 0, "ko": "오후 1시에 무엇이 배송될 것인가?"}, {"n": 66, "q": "What does the man ask the woman to do?", "opts": ["Verify a recent order", "Clean up a job site", "Organize a team", "Provide a signature"], "ans": 3, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가?"}, {"n": 67, "q": "Look at the graphic. Which room will be renovated tomorrow?", "opts": ["Room 101", "Room 102", "Room 103", "Room 104"], "ans": 3, "ko": "시각 자료를 보시오. 내일 어떤 방이 보수될 것인가?"}], "script": [{"sp": "M", "en": "A shipment is going to be delivered to our job site at 1 P.M. It'll include wooden boards, which we'll install on the floors later. I'll be running an errand then, so you'll have to sign off on the order when it gets here.", "ko": "우리 작업장으로 오후 1시에 수송품이 배송될 거예요. 거기엔 목판이 포함되어 있을 텐데, 우리는 그걸 나중에 바닥에 설치할 거예요. 제가 그때 심부름을 할 예정이라서, 주문품이 여기 도착하면 당신이 그것에 서명을 하여 승인해야 할 거예요."}, {"sp": "W", "en": "That's not an issue. Where do you want the delivered items to be stored?", "ko": "그건 문제가 되지 않아요. 배송된 물품을 어디에 보관하길 원하시나요?"}, {"sp": "M", "en": "Put them in the room on the first floor that we're renovating tomorrow.", "ko": "우리가 내일 보수할 1층의 방에 놔주세요."}, {"sp": "W", "en": "Um, is that the one right beside the elevator?", "ko": "음, 엘리베이터 바로 옆에 있는 것인가요?"}, {"sp": "M", "en": "No. The room between the storage closet and the conference room.", "ko": "아니요. 수납장과 회의실 사이의 방이에요."}, {"sp": "W", "en": "OK, I'll do that. I'll also move the tools and any other equipment we'll need.", "ko": "알겠어요, 그렇게 할게요. 우리가 필요로 할 도구들과 다른 장비들 또한 옮겨 놓을게요."}], "gimg": "hk_t9_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M-Ca, W-Br", "audio": "Test09_68-70.mp3", "qs": [{"n": 68, "q": "What do the speakers agree to do?", "opts": ["Change a lecture topic", "Travel to an event together", "Ask for a deadline extension", "Get advice from an organizer"], "ans": 1, "ko": "화자들은 무엇을 하기로 동의하는가?"}, {"n": 69, "q": "Look at the graphic. Which speaker is the man looking forward to?", "opts": ["Brett Chambers", "Sandra Harris", "Margaret Block", "Antonia Garcia"], "ans": 3, "ko": "시각 자료를 보시오. 남자는 어떤 연설자를 기대하고 있는가?"}, {"n": 70, "q": "How did the man receive information about a talk?", "opts": ["By asking event staff", "By registering for notifications", "By streaming a video online", "By downloading a newsletter"], "ans": 1, "ko": "남자는 어떻게 강연에 관한 정보를 받았는가?"}], "script": [{"sp": "M", "en": "Good morning, Stella. I heard you're going to the Interior Decorating Conference this Saturday. If you're interested, I can drive you there.", "ko": "안녕하세요, Stella. 당신이 이번 주 토요일에 실내 장식 컨퍼런스에 갈 예정이라고 들었어요. 관심이 있으시면, 제가 그곳으로 데려다 드릴 수 있어요."}, {"sp": "W", "en": "I registered for the first seminar of the day, which means you'd have to arrive pretty early. If that's fine, I'll take you up on your offer.", "ko": "저는 그날의 첫 번째 강연에 등록했는데, 이는 당신이 꽤 일찍 도착해야 한다는 것을 의미해요. 그게 괜찮으시다면 당신의 제안을 받아들일게요."}, {"sp": "M", "en": "No problem. That'll give me time to check out some stalls. By the way, are you going to attend the talk about lighting? It looks really interesting. A renowned expert is leading it.", "ko": "문제 없어요. 그건 제게 가판대들을 살펴볼 시간을 줄 거예요. 그건 그렇고, 조명에 대한 강연에 참석하실 건가요? 굉장히 흥미로워 보여요. 저명한 전문가가 이끈다고 해요."}, {"sp": "W", "en": "Really? I hadn't heard about that.", "ko": "정말이요? 저는 그것에 대해 듣지 못했어요."}, {"sp": "M", "en": "The speaker was only added to the program yesterday due to a scheduling conflict.", "ko": "그 연설자는 일정이 겹치는 바람에 어제가 되어서야 예정표에 추가되었어요."}, {"sp": "W", "en": "How did you learn about it then?", "ko": "그럼 그것에 대해 어떻게 아셨나요?"}, {"sp": "M", "en": "Oh, I signed up to receive text updates about the conference.", "ko": "아, 저는 컨퍼런스에 대해 문자로 최신 정보를 받는 것을 신청했었어요."}], "gimg": "hk_t9_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test09_71-73.mp3", "qs": [{"n": 71, "q": "What does the speaker say listeners should include in a message?", "opts": ["A building name", "A unit number", "An available date", "A price range"], "ans": 1, "ko": "화자는 청자들이 메시지에 무엇을 포함해야 한다고 말하는가?"}, {"n": 72, "q": "Why should listeners dial a different number?", "opts": ["To learn about available units", "To set up an automatic payment", "To report an emergency", "To offer some feedback"], "ans": 2, "ko": "청자들은 왜 다른 번호로 전화해야 하는가?"}, {"n": 73, "q": "Who is Tom Meynard?", "opts": ["A building owner", "A leasing agent", "An administrative assistant", "A maintenance supervisor"], "ans": 3, "ko": "Tom Meynard는 누구인가?"}], "script": [{"sp": "M", "en": "You've reached the maintenance office of Mitcham Heights Apartments. We are not able to take your call right now, but we will be sure to get back to you as soon as possible. If you are contacting us regarding a non-urgent matter, please leave a message after the beep. Be sure to include your name, your unit number, and a detailed description of your issue. If you are experiencing a maintenance emergency, please hang up and dial 555-3948 to reach Tom Meynard, the building's maintenance manager. He will make the necessary arrangements to assist you immediately.", "ko": "Mitcham Heights 아파트의 관리 사무실입니다. 저희는 현재 귀하의 전화를 받을 수 없으나, 가능한 한 빨리 귀하께 다시 연락드리도록 하겠습니다. 만약 긴급하지 않은 사안에 관해 연락을 주신 것이라면, 삐 소리 후 메시지를 남겨주시기 바랍니다. 반드시 귀하의 이름과 아파트 호수, 그리고 문제에 대한 자세한 설명을 포함해주시기 바랍니다. 만약 귀하께서 정비 관련 긴급 상황을 겪고 계시다면, 전화를 끊고 건물의 정비 관리자인 Tom Meynard에게 연락하기 위해 555-3948로 전화를 걸어주시기 바랍니다. 그가 귀하를 즉시 도와드리기 위해 필요한 준비를 할 것입니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test09_74-76.mp3", "qs": [{"n": 74, "q": "Where most likely is the meeting taking place?", "opts": ["At a design studio", "At a retail outlet", "At a government office", "At a financial institution"], "ans": 1, "ko": "회의는 어디에서 일어나는 것 같은가?"}, {"n": 75, "q": "What does the speaker mean when she says, \"you should act quickly\"?", "opts": ["A job posting is about to expire.", "An incentive will not last long.", "A workshop will take place soon.", "A payment due date is approaching."], "ans": 1, "ko": "화자는 \"서두르셔야 합니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 76, "q": "What does the speaker suggest doing?", "opts": ["Applying for a credit card", "Transferring funds to a bank", "Participating in a meeting", "Providing information to customers"], "ans": 3, "ko": "화자는 무엇을 하라고 제안하는가?"}], "script": [{"sp": "W", "en": "OK, everyone . . . Gather around for just a moment. I want you all to promote our new credit card partnership with Silver Card to shoppers. After signing up for a credit card, customers can receive 30 percent off their first purchase as well as 5 percent off each one after that . . . Any employee who gets more than 20 customers to register will receive a $1,000 bonus. But since we'll only be doing this for a month, you should act quickly. So, you should tell each customer you interact with about the card.", "ko": "자, 여러분… 잠시 모여주시기 바랍니다. 저는 여러분 모두가 Silver Card사와의 새로운 신용 카드 제휴를 쇼핑객들에게 홍보해주시길 바랍니다. 신용 카드를 신청한 후, 고객들은 첫 구매의 30퍼센트 할인뿐만 아니라 그 이후 각 구매에 대한 5퍼센트 할인도 받을 수 있습니다… 20명 이상의 고객들을 등록하도록 만든 직원은 1000달러의 보너스를 받게 될 것입니다. 그러나 우리는 이것을 한 달 동안만 할 것이기 때문에, 서두르셔야 합니다. 그러니, 여러분이 교류하는 각 고객들에게 카드에 대해 말씀하셔야 합니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test09_77-79.mp3", "qs": [{"n": 77, "q": "What will the listeners do during a tour?", "opts": ["Stop by a public park", "Meet with a famous architect", "Explore a city center", "Take a shuttle across town"], "ans": 2, "ko": "관광 중에 청자들이 할 것을 묻는 문제이므로, 질문의 핵심어구(do during a tour)와 관련된 내용을 주의 깊게 듣는다. \"We will mostly walk around the downtown area today\"라며 오늘 주로 도심 지역을 걸어 다닐 예정이라고 하였다. 따라서 정답은 (C) Explore a city center이다. [바꾸어 표현하기] downtown area 도심 지역 → city center 도시 중심가"}, {"n": 78, "q": "What does the speaker say will happen later?", "opts": ["Participants will visit a restaurant.", "A group will stop at a gift shop.", "Some tickets will be collected.", "Some headsets will be distributed."], "ans": 0, "ko": "화자가 나중에 일어날 일이라고 말하는 것을 묻는 문제이므로, 질문의 핵심어구(will happen later)와 관련된 내용을 주의 깊게 듣는다. \"We'll also stop by the historic eatery Pizzeria Quatro for lunch.\"라며 점심 식사를 하기 위해 역사적인 음식점인 Pizzeria Quatro에 들를 것이라고 하였다. 따라서 정답은 (A) Participants will visit a restaurant이다."}, {"n": 79, "q": "What does the speaker ask the listeners to do?", "opts": ["Cross a street", "Take photographs", "Dress appropriately", "Remain close together"], "ans": 3, "ko": "화자가 청자들에게 요청한 것을 묻는 문제이므로, 지문에서 요청과 관련된 표현이 포함된 문장을 주의 깊게 듣는다. \"please stay together while we walk through the streets\"라며 거리를 걸어 다니는 동안 붙어 있으라고 요청하였다. 따라서 정답은 (D) Remain close together이다."}], "script": [{"sp": "W", "en": "My name is Anita, and I'd like to welcome you all to Citystep's architecture tour of downtown Chicago. We will mostly walk around the downtown area today, where you will see one of the oldest skyscrapers in the world. We'll also stop by the historic eatery Pizzeria Quatro for lunch. While there, I'll talk about the city's influential Italian immigrant community. Feel free to ask me any questions you might have during the tour. And please stay together while we walk through the streets.", "ko": "제 이름은 Anita이고, 시카고 도심에서 열리는 Citystep의 건축 관광에 오신 여러분 모두를 환영합니다. 저희는 오늘 주로 도심 지역을 걸어 다닐 예정인데, 그곳에서 세계에서 가장 오래된 고층 건물들 중 하나를 보실 것입니다. 저희는 또한 점심 식사를 하기 위해 역사적인 음식점인 Pizzeria Quatro에 들를 것입니다. 그곳에 있는 동안, 제가 이 도시의 영향력 있는 이탈리아의 이민자 집단에 대해 이야기해 드리겠습니다. 관광 중에 생길 수 있는 질문들을 언제든 자유롭게 물어보십시오. 그리고 거리를 걸어 다니는 동안 붙어 계시기 바랍니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test09_80-82.mp3", "qs": [{"n": 80, "q": "Why does the speaker thank the listener?", "opts": ["She corrected a miscommunication.", "She returned a missing office item.", "She submitted an article on short notice.", "She replied to a business proposal."], "ans": 2, "ko": "화자는 왜 청자에게 감사하는가?"}, {"n": 81, "q": "What does the speaker want the listener to do?", "opts": ["Move a deadline forward", "Review a reporter's work", "Give some publishing advice", "Write a weekly column"], "ans": 3, "ko": "화자는 청자가 무엇을 하기를 원하는가?"}, {"n": 82, "q": "Why is the listener asked to return the call?", "opts": ["To schedule an appointment", "To discuss some contract changes", "To brainstorm some topics", "To explain an issue with a résumé"], "ans": 2, "ko": "청자는 왜 다시 전화를 하도록 요청받는가?"}], "script": [{"sp": "M", "en": "Hello, Ms. Rahim. This is Ross Manuel, the assistant editor at The Broadway Times. First of all, I'd like to thank you for turning in your last article on such short notice. Everyone here is very impressed with it. I'm calling to see if you would be interested in writing a column for our newspaper each week. If that sounds like an offer you'd like to accept, please call back. We'll have to begin thinking up topics right away for your first couple of articles as any ideas we come up with will have to be approved by the chief editor.", "ko": "안녕하세요, Ms. Rahim. 저는 The Broadway Times지의 보조 편집자인 Ross Manuel입니다. 먼저, 갑작스러운 요청에도 당신의 최종 원고를 제출해 주신 것에 대해 감사드리고 싶습니다. 이곳의 모든 사람들이 그것에 매우 감명받았습니다. 혹시 당신이 저희 신문에 매주 칼럼을 쓰는 것에 대해 관심이 있으신지 알아보기 위해 전화드립니다. 만약 그것이 당신이 수락할 만한 제안처럼 들리신다면, 다시 전화주십시오. 저희가 생각하는 어떤 아이디어든 최고 편집자에게 승인이 되어야 하기 때문에, 처음 몇 개의 기사들을 위한 주제들을 바로 생각하기 시작해야 할 것입니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test09_83-85.mp3", "qs": [{"n": 83, "q": "Which department does the speaker work in?", "opts": ["Shipping", "Accounting", "Acquisitions", "Marketing"], "ans": 2, "ko": "화자는 어느 부서에서 일하는가?"}, {"n": 84, "q": "What problem does the speaker mention?", "opts": ["A business failed an evaluation.", "A competitor has opened a new branch.", "A contract has not been renewed.", "An order will arrive later than expected."], "ans": 0, "ko": "화자는 무슨 문제를 언급하는가?"}, {"n": 85, "q": "What does the speaker imply when she says, \"Kimani Farms has been one of our most reliable sources\"?", "opts": ["She hopes to meet with a business owner.", "She wants a company to receive a contract extension.", "She regrets that a supplier must be replaced.", "She expects an order to be fulfilled on time."], "ans": 2, "ko": "화자는 \"Kimani 농장은 우리가 가장 믿을 수 있는 공급처였습니다\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "W", "en": "Good afternoon, Mr. Maxwell. This is Faraja from the acquisitions department. I know you're on personal leave until tomorrow, but I want to let you know that I had an important discussion with a representative from Kimani Farms this afternoon. Apparently the . . . ah . . . the farm had an annual inspection yesterday, and it didn't meet the requirements for its produce to be classified as organic. That means we'll have to stop buying tomatoes and carrots from them until the situation changes, which will be a big deal for us. Kimani Farms has been one of our most reliable sources.", "ko": "안녕하세요, Mr. Maxwell. 저는 구매 부서의 Faraja입니다. 당신이 내일까지 휴가라는 것을 알지만, 오늘 오후에 Kimani 농장의 대표와 중요한 논의를 했다는 것을 알려드리고 싶습니다. 듣자 하니 그… 아… 그 농장이 어제 연례 조사를 받았는데, 그들의 농산물이 유기농으로 분류되기 위한 요건들을 충족하지 못했습니다. 그것은 상황이 바뀔 때까지 우리가 토마토와 당근을 그들에게 구매하는 것을 중단해야 한다는 것을 의미하는데, 이것은 우리에게 큰 문제가 될 것입니다. Kimani 농장은 우리가 가장 믿을 수 있는 공급처였습니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test09_86-88.mp3", "qs": [{"n": 86, "q": "What does Ride Easy plan to do in May?", "opts": ["Launch an advertising campaign", "Move to another location", "Organize an event", "Partner with another firm"], "ans": 1, "ko": "Ride Easy는 5월에 무엇을 할 계획인가?"}, {"n": 87, "q": "What is mentioned about Mayor Paul Crane?", "opts": ["He will attend a grand opening.", "He released a public statement.", "He invested in infrastructure.", "He approved bicycle regulations."], "ans": 2, "ko": "Paul Crane 시장에 관해 무엇이 언급되는가?"}, {"n": 88, "q": "According to the speaker, who will Ms. Linden most likely hire?", "opts": ["Accountants", "Models", "Technicians", "Salespeople"], "ans": 2, "ko": "화자에 따르면, Ms. Linden은 누구를 고용할 것 같은가?"}], "script": [{"sp": "M", "en": "In local news, the longstanding bike shop Ride Easy has announced plans to relocate in May. The shop's next space will be almost twice as large and is situated near the intersection of Frey Road and First Avenue. Owner Sally Linden's decision was prompted by a dramatic increase in sales over the previous two years. According to Ms. Linden, the business is more profitable than ever, and she attributes this to Rockshire Mayor Paul Crane's investment in bike lanes across the city. With the added room, shoppers will be able to pick from more bicycle models, and Ms. Linden is going to hire additional repair technicians.", "ko": "지역 뉴스로, 오랫동안 운영된 자전거 상점인 Ride Easy가 5월에 이전한다는 계획을 발표했습니다. 상점의 다음 장소는 거의 두 배가 넓을 것이고 Frey가와 1번가의 교차로 근처에 위치합니다. 소유주인 Sally Linden의 결정은 지난 2년에 걸친 엄청난 매출의 증가에 의해 촉구되었습니다. Ms. Linden에 따르면, 가게는 그 어느 때보다 많은 수익을 얻고 있으며, 그녀는 이것을 Rockshire 시장인 Paul Crane의 도시 전역에 걸친 자전거 도로에 대한 투자 덕분이라고 생각합니다. 늘어난 공간으로 인해, 쇼핑객들은 더 많은 자전거 모델들 가운데서 선택할 수 있게 될 것이고, Ms. Linden은 추가로 수리 기술자들을 고용할 예정입니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test09_89-91.mp3", "qs": [{"n": 89, "q": "What is the purpose of the event?", "opts": ["To congratulate a colleague on a promotion", "To welcome some new business partners", "To thank several company leaders", "To celebrate an employee's retirement"], "ans": 3, "ko": "행사의 목적은 무엇인가?"}, {"n": 90, "q": "What does the speaker imply when he says, \"it has proven to be a good decision\"?", "opts": ["An expansion has been profitable.", "A merger was approved by authorities.", "A business received positive publicity.", "A firm has recruited impressive candidates."], "ans": 0, "ko": "화자는 \"그것은 좋은 결정이라고 입증되었습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 91, "q": "What will most likely happen next?", "opts": ["A gift will be given.", "A speech will be made.", "A meal will get under way.", "A development will be explained."], "ans": 0, "ko": "다음에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "Welcome to Daniel Simon's farewell party. After spending 30 years at Bremer Travel Agency, Mr. Simon is going into retirement. He was responsible for establishing satellite offices in several overseas locations, including two in Thailand. The company opened these branches to bring in more earnings, and after a few years of operations, it has proven to be a good decision. OK, Mr. Simon, I'd like to invite you to join me up here in front of everyone. I want to present you with a gold watch to commemorate your time with the company.", "ko": "Daniel Simon의 송별 파티에 오신 것을 환영합니다. 지난 30년을 Bremer 여행사에서 보낸 후, Mr. Simon은 은퇴를 합니다. 그는 태국에 있는 두 곳을 포함한 여러 해외 지역의 지사 설립을 담당했습니다. 회사는 더 많은 수입을 벌어들이기 위해 이러한 지사들을 열었고, 몇 년 동안의 운영 후에 그것은 좋은 결정이라고 입증되었습니다. 자, Mr. Simon, 여기 모든 사람들의 앞으로 올라와 주실 것을 부탁드립니다. 저는 회사에서의 당신의 시간을 기념하기 위해 당신께 금시계를 드리고 싶습니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "M-Am", "audio": "Test09_92-94.mp3", "qs": [{"n": 92, "q": "Where does the speaker most likely work?", "opts": ["At a bank", "At an auto repair shop", "At a rental agency", "At a retailer"], "ans": 2, "ko": "화자는 어디에서 일하는 것 같은가?"}, {"n": 93, "q": "According to the speaker, what information is not required?", "opts": ["Birth date", "Phone number", "Insurance provider", "Home address"], "ans": 2, "ko": "화자에 따르면, 어떤 정보가 요구되지 않는가?"}, {"n": 94, "q": "Why should the listeners press a green button?", "opts": ["To save some details", "To request technical support", "To print a document", "To close a Web page"], "ans": 0, "ko": "청자들은 왜 초록색 버튼을 눌러야 하는가?"}], "script": [{"sp": "M", "en": "Since the process for creating a customer account at our vehicle rental shop has changed, I want to walk you all through the new steps. First, click on this red button at the top left of the computer screen. Doing so will open a special digital form, which you can use to enter the customer's personal information. After that, insert the name, date of birth, phone number, and home address into the relevant text fields. Ignore the field asking about the name of the insurance provider. Once you've inputted the necessary information, click the green button at the bottom. This will save everything in our system.", "ko": "우리 자동차 대여점의 고객 계정을 만드는 과정이 변경되었기 때문에 새로운 단계들을 여러분 모두에게 보여드리고 싶습니다. 우선, 컴퓨터 스크린 왼쪽 상단에 있는 이 빨간색 버튼을 누르십시오. 그렇게 하면 특정한 디지털 양식이 열릴 텐데, 그것을 고객의 개인 정보를 입력하는 데에 사용할 수 있습니다. 그 후에, 이름, 생일, 전화번호, 그리고 집 주소를 관련된 텍스트 필드에 입력하십시오. 보험 회사의 이름을 묻는 필드는 무시하셔도 됩니다. 필요한 정보를 입력하시고 나면, 하단의 초록색 버튼을 누르십시오. 이것은 우리의 시스템에 모든 것을 저장할 것입니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "W-Au", "audio": "Test09_95-97.mp3", "qs": [{"n": 95, "q": "Why has an event been rescheduled?", "opts": ["To avoid bad weather", "To attract more participants", "To secure a bigger venue", "To raise additional money"], "ans": 0, "ko": "행사의 일정이 왜 조정되었는가?\n(A) 악천후를 피하기 위해\n(B) 더 많은 참가자들을 모으기 위해\n(C) 더 큰 장소를 확보하기 위해\n(D) 추가 자금을 모으기 위해"}, {"n": 96, "q": "What does the speaker say another group did?", "opts": ["Responded to an invitation", "Missed a deadline", "Booked a space", "Canceled a gathering"], "ans": 2, "ko": "화자는 다른 단체가 무엇을 했다고 말하는가?\n(A) 초대에 응했다.\n(B) 마감 기한을 놓쳤다.\n(C) 공간을 예약했다.\n(D) 모임을 취소했다."}, {"n": 97, "q": "Look at the graphic. What time will the awards ceremony most likely be held?", "opts": ["10:00 A.M.", "11:30 A.M.", "12:00 P.M.", "12:30 P.M."], "ans": 2, "ko": "시각 자료를 보시오. 시상식은 몇 시에 열릴 것 같은가?\n(A) 오전 10시\n(B) 오전 11시 30분\n(C) 오후 12시\n(D) 오후 12시 30분"}], "script": [{"sp": "W", "en": "May I have your attention, everyone? On July 1, I e-mailed you all the schedule for tomorrow's employee outing at Oak Park downtown. However, a last-minute revision has been made to the schedule. Due to the thunderstorms expected on July 3, we're now gonna hold the event in a pavilion in the park. Unfortunately, the structure has already been reserved by another group for the late afternoon, so we'll have to finish earlier than planned. Therefore, we'll skip the relay race and give out staff awards then instead. I hope this isn't too much of a disappointment.", "ko": "모두 주목해주시겠습니까? 7월 1일에 제가 시내 근처의 Oak 공원에서 내일 있을 직원 야유회의 일정표를 모두에게 이메일로 보냈습니다. 하지만, 일정표에 막판 수정이 이뤄졌습니다. 7월 3일에 있을 것으로 예상되는 폭풍우로 인해 공원의 별관에서 이 행사를 열고자 합니다. 안타깝게도, 해당 건물이 늦은 오후에 다른 단체에 의해 예약이 되어 있어서, 계획된 것보다 일찍 마쳐야 할 것 같습니다. 따라서, 릴레이 경주는 생략하고 대신 그때 직원분들에게 상을 나눠드리도록 하겠습니다. 이것으로 인해 너무 크게 실망하지 않으셨으면 합니다."}], "gimg": "hk_t9_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "W-Br", "audio": "Test09_98-100.mp3", "qs": [{"n": 98, "q": "What will be handed out to promote Customer Appreciation Day?", "opts": ["Match tickets", "Jerseys", "Glass cups", "Headwear"], "ans": 3, "ko": "고객 감사일을 홍보하기 위해 무엇이 배부될 것인가?\n(A) 경기 티켓\n(B) 운동복\n(C) 유리컵\n(D) 모자"}, {"n": 99, "q": "Look at the graphic. Which food item can some attendees receive for free?", "opts": ["A hotdog", "A hamburger", "A pizza slice", "A salad"], "ans": 0, "ko": "시각 자료를 보시오. 일부 참석자들은 어느 음식을 무료로 받을 수 있는가?\n(A) 핫도그\n(B) 햄버거\n(C) 피자 한 조각\n(D) 샐러드"}, {"n": 100, "q": "What is mentioned about the wristbands?", "opts": ["They come in various colors.", "They can be bought in advance.", "They must be picked up in person.", "They are free of charge."], "ans": 0, "ko": "팔찌에 관해 무엇이 언급되는가?\n(A) 다양한 색깔로 나온다.\n(B) 미리 구매할 수 있다.\n(C) 직접 가져가야 한다.\n(D) 무료이다."}], "script": [{"sp": "W", "en": "As you know, today is our annual Customer Appreciation Day at our stadium. To promote the event, we'll be handing out baseball hats featuring the Blue Bird team logo. Plus, children under the age of 12 can receive one free food item worth $5 or less from any vendor stall here in the stadium. When fans wearing a blue wristband take advantage of this offer, mark their wristband with an 'X'. Visitors with wristbands printed in any other color—such as red or white—don't qualify.", "ko": "여러분도 아시다시피, 오늘은 우리 경기장의 연례 고객 감사일입니다. 이 행사를 홍보하기 위해, 우리는 Blue Bird팀의 로고가 포함된 야구 모자를 나눠줄 것입니다. 게다가, 12살 미만의 어린이들은 경기장의 어느 판매점에서든 5달러 이하에 해당하는 무료 음식 한 가지를 받을 수 있습니다. 파란색 팔찌를 착용한 팬들이 이 제공 사항을 이용할 때, 그들의 팔찌에 'X' 표시를 해주기 바랍니다. 빨간색이나 하얀색과 같은 다른 색으로 인쇄된 팔찌를 차고 있는 방문객들은 해당되지 않습니다."}], "gimg": "hk_t9_g98.jpg"}]};
